   732|  const attempts: string[] = [];
   733|
   734|  // Strategy 1 — in-process import (most robust in the tsx-hosted container).
   735|  try {
   736|    await import(`${targetUrl}?ivxsmoke=${Date.now()}`);
   737|    return {
   738|      block: 35,
   739|      command: `in-process import-smoke ${repoFile}`,
   740|      cwd: '.',
   741|      ok: true,
   742|      exitCode: 0,
   743|      durationMs: Date.now() - started,
   744|      stdoutTail: `IVX_IMPORT_SMOKE_OK ${repoFile}`,
   745|      stderrTail: '',
   746|      error: null,
   747|    };
   748|  } catch (error) {
   749|    attempts.push(`in-process: ${safeErrorMessage(error)}`);
   750|  }
   751|
   752|  // Strategy 2 — isolated child process via the tsx CLI.
   753|  const child = await runChildImportSmoke(projectRoot, nodePath, repoFile);
   754|  if (child.ok) {
   755|    return {
   756|      block: 35,
   757|      command: `child import-smoke ${repoFile}`,
   758|      cwd: '.',
   759|      ok: true,
   760|      exitCode: 0,
   761|      durationMs: Date.now() - started,
   762|      stdoutTail: `IVX_IMPORT_SMOKE_OK ${repoFile}`,
   763|      stderrTail: '',
   764|      error: null,
   765|    };
   766|  }
   767|  attempts.push(child.detail);
   768|
   769|  return {
   770|    block: 35,
   771|    command: `import-smoke ${repoFile}`,
   772|    cwd: '.',
   773|    ok: false,
   774|    exitCode: null,
   775|    durationMs: Date.now() - started,
   776|    stdoutTail: '',
